/** Relational roadmap schema v2 with maturity classification, horizon partitioning, authority scoping, evidence requirements, and unattended execution policies. Maps ADRs to campaigns, missions, lanes, and tasks across four execution horizons. */
export interface Relational_RoadmapV2 {
  /** Schema identifier */
  "schema_version": "rig.relay.roadmap.v2";
  /** Roadmap title */
  "title": string;
  /** Roadmap description */
  "description"?: string;
  /** Roadmap status */
  "status": "planned" | "active" | "completed" | "blocked" | "cancelled";
  /** Four-horizon partitioning of the roadmap */
  "horizons"?: {
  /** Fully specified tasks, may run unattended */
  "committed"?: {
  "campaigns"?: string[];
  /** Target number of ready tasks (150-300) */
  "ready_tasks_target"?: number;
};
  /** Missions and acceptance gates with provisional tasks */
  "planned"?: {
  "campaigns"?: string[];
  /** Target number of planned tasks blocked behind gates (300-500) */
  "planned_tasks_target"?: number;
};
  /** Campaigns with dependency ordering, missions defined but tasks not locked */
  "strategic"?: {
  "campaigns"?: string[];
};
  /** Questions not yet authorized for implementation */
  "research"?: {
  "campaigns"?: string[];
  "research_questions"?: string[];
};
};
  /** Roadmap creation timestamp */
  "created_at": string;
  /** Roadmap last update timestamp */
  "updated_at"?: string;
  /** List of ADRs related to this roadmap */
  "adrs"?: AdrReference[];
  /** List of campaigns within this roadmap */
  "campaigns": Campaign[];
  /** Metadata and tags */
  "meta"?: {
  "tags"?: string[];
  "owner"?: string;
  "reviewers"?: string[];
};
}

