/** Meta-schema that validates all project JSON schemas for 2020-12 compliance and project conventions. */
export interface OpenCode_Schema_Meta_Schema {
  /** JSON Schema version URI. Must point to draft/2020-12. */
  "$schema": "https://json-schema.org/draft/2020-12/schema";
  /** Stable absolute URI identifying the schema. */
  "$id": string;
  /** Human-readable schema title in PascalCase. */
  "title": string;
  /** Schema purpose and scope. */
  "description": string;
  /** JSON Schema type keyword. */
  "type"?: "object" | "array" | "string" | "number" | "integer" | "boolean" | "null";
  /** Object property definitions. Keys must use camelCase. */
  "properties"?: Record<string, Record<string, unknown>>;
  /** Reusable schema definitions. Keys must use PascalCase. */
  "$defs"?: Record<string, {
  /** Definition type. */
  "type": string;
  /** What this definition represents. */
  "description": string;
}>;
  /** List of required properties. */
  "required"?: string[];
  /** Whether additional properties are allowed. */
  "additionalProperties"?: boolean;
  /** Enumeration of allowed values. */
  "enum"?: string[];
  /** Regex pattern for string validation. */
  "pattern"?: string;
  /** Semantic format (e.g., date-time, uri, email). */
  "format"?: string;
  /** Minimum numeric value. */
  "minimum"?: number;
  /** Maximum numeric value. */
  "maximum"?: number;
  /** Minimum string length. */
  "minLength"?: number;
  /** Maximum string length. */
  "maxLength"?: number;
  /** Schema for array items. */
  "items"?: Record<string, unknown>;
  /** Example values. */
  "examples"?: unknown;
  /** Arbitrary comment. */
  "$comment"?: string;
}
